package com.hospital.management.util;import java.util.*;
/** Authoritative appointment state machine. */
public final class AppointmentStatusTransition {private static final Map<String,Map<String,String>>M=Map.of("SCHEDULED",Map.of("confirm","CONFIRMED","cancel","CANCELLED"),"CONFIRMED",Map.of("complete","COMPLETED","cancel","CANCELLED","no_show","NO_SHOW"));private AppointmentStatusTransition(){}public static Optional<String> target(String current,String action){if(current==null||action==null)return Optional.empty();return Optional.ofNullable(M.getOrDefault(current.toUpperCase(Locale.ROOT),Map.of()).get(action.toLowerCase(Locale.ROOT)));}public static boolean isTerminal(String status){return Set.of("COMPLETED","CANCELLED","NO_SHOW").contains(status==null?"":status.toUpperCase(Locale.ROOT));}}
